import java.util.concurrent.*;
// Thread-safe word frequency with ConcurrentHashMap.merge

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
public class App {
    public static void main(String[] args) throws InterruptedException {
        ConcurrentHashMap<String, Integer> freq = new ConcurrentHashMap<>();
        ExecutorService pool = Executors.newFixedThreadPool(4);

        List<List<String>> batches = Arrays.asList(
            Arrays.asList("apple", "apple"),
            Arrays.asList("banana", "cherry"),
            Arrays.asList("banana", "apple"),
            Arrays.asList("cherry", "cherry")
        );

        for (List<String> batch : batches) {
            pool.submit(() -> {
                for (String word : batch) freq.merge(word, 1, Integer::sum);
            });
        }
        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);

        new TreeMap<>(freq).forEach((word, count) ->
            System.out.println(word + ": " + count));
    }
}

