import java.util.*;
import java.util.concurrent.*;
// computeIfAbsent for thread-safe grouping

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
public class App {
    public static void main(String[] args) throws InterruptedException {
        ConcurrentHashMap<String, List<String>> byDept = new ConcurrentHashMap<>();
        ExecutorService pool = Executors.newFixedThreadPool(4);

        Object[][] employees = {
            {"Aisha","Engineering"}, {"Raj","Sales"},
            {"Priya","Engineering"}, {"Vikram","Marketing"}, {"Anita","Sales"}
        };

        for (Object[] emp : employees) {
            final String name = (String)emp[0], dept = (String)emp[1];
            pool.submit(() -> {
                // computeIfAbsent is atomic — only one CopyOnWriteArrayList created per dept
                byDept.computeIfAbsent(dept, k -> new CopyOnWriteArrayList<>()).add(name);
            });
        }
        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);

        new TreeMap<>(byDept).forEach((dept, names) -> {
            List<String> sorted = new ArrayList<>(names);
            Collections.sort(sorted);
            System.out.println(dept + ": " + sorted);
        });
    }
}

import java.util.concurrent.*;
public class App {
    public static void main(String[] args) throws InterruptedException {
        BlockingQueue<String> queue = new LinkedBlockingQueue<>(3);

        Thread producer = new Thread(() -> {
            try {
                for (int i = 1; i <= 5; i++) {
                    String task = "Task-" + i;
                    System.out.println("Producing: " + task);
                    queue.put(task);  // blocks if queue full
                }
                queue.put("DONE");  // sentinel
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        Thread consumer = new Thread(() -> {
            try {
                while (true) {
                    String task = queue.take();  // blocks if empty
                    if ("DONE".equals(task)) break;
                    System.out.println("Processing: " + task);
                    Thread.sleep(50);  // simulate work
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        producer.start();
        consumer.start();
        producer.join();
        consumer.join();
        System.out.println("All done");
    }
}

