import java.util.concurrent.atomic.*;
// Thread-safe lazy cache

exercises.expected_solution:
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
public class App {
    static ConcurrentHashMap<String, String> cache = new ConcurrentHashMap<>();
    static AtomicInteger computeCount = new AtomicInteger(0);

    static String expensiveCompute(String key) {
        System.out.println("Computing for: '" + key + "'");
        computeCount.incrementAndGet();
        try { Thread.sleep(200); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        return key.toUpperCase();
    }

    public static void main(String[] args) throws InterruptedException {
        ExecutorService pool = Executors.newFixedThreadPool(3);
        String key = "hyderabad";

        // 3 concurrent requests for the same key:
        for (int i = 0; i < 3; i++) {
            pool.submit(() -> {
                String result = cache.computeIfAbsent(key, App::expensiveCompute);
                System.out.println("Result for '" + key + "': " + result);
            });
        }
        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("Total computations: " + computeCount.get());
    }
}

