exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.CopyOnWriteArrayList;
public class App {
    public static void main(String[] args) throws InterruptedException {
        CopyOnWriteArrayList<String> listeners = new CopyOnWriteArrayList<>();
        listeners.add("L1"); listeners.add("L2"); listeners.add("L3");
        System.out.println("Listeners at start: " + listeners.size());

        // Publisher iterates and notifies:
        Thread publisher = new Thread(() -> {
            for (String listener : listeners) {  // iterates snapshot — safe
                System.out.println("Notified " + listener);
                try { Thread.sleep(50); } catch (InterruptedException e) { return; }
            }
        });

        // Concurrent modifier removes a listener while publisher iterates:
        Thread modifier = new Thread(() -> {
            try { Thread.sleep(60); } catch (InterruptedException e) { return; }
            listeners.remove("L2");  // modifies underlying array — copy-on-write
        });

        publisher.start(); modifier.start();
        publisher.join(); modifier.join();
        System.out.println("Listeners after modify: " + listeners.size());
    }
}

