// Multi-producer, multi-consumer with bounded BlockingQueue

exercises.expected_solution:
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
public class App {
    static final String POISON = "__DONE__";
    public static void main(String[] args) throws InterruptedException {
        BlockingQueue<String> queue = new LinkedBlockingQueue<>(5);
        AtomicInteger processed = new AtomicInteger(0);
        int numConsumers = 3;

        // Producers
        Thread[] producers = {
            new Thread(() -> {
                try {
                    for (int i=1;i<=10;i++) { System.out.println("Produced Task-P1-"+i); queue.put("Task-P1-"+i); }
                } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }),
            new Thread(() -> {
                try {
                    for (int i=1;i<=10;i++) { System.out.println("Produced Task-P2-"+i); queue.put("Task-P2-"+i); }
                } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            })
        };

        // Consumers
        Thread[] consumers = new Thread[numConsumers];
        for (int c=0;c<numConsumers;c++) {
            final String name = "Worker-"+(c+1);
            consumers[c] = new Thread(() -> {
                try {
                    while (true) {
                        String task = queue.take();
                        if (POISON.equals(task)) { queue.put(POISON); break; }
                        processed.incrementAndGet();
                        System.out.println(name+" processed "+task);
                    }
                } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            });
        }

        for (Thread t : consumers) t.start();
        for (Thread t : producers) t.start();
        for (Thread t : producers) t.join();
        queue.put(POISON);  // single sentinel consumed and re-queued for all workers
        for (Thread t : consumers) t.join();
        System.out.println("All " + processed.get() + " tasks processed");
    }
}

