import java.util.*;
import java.util.concurrent.*;
// Thread-safe bounded cache with eviction

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
class BoundedCache {
    private final int capacity;
    private final ConcurrentHashMap<String, String> map = new ConcurrentHashMap<>();
    private final LinkedBlockingDeque<String> insertionOrder = new LinkedBlockingDeque<>();

    BoundedCache(int capacity) { this.capacity = capacity; }

    synchronized void put(String key, String value) {
        if (map.containsKey(key)) {
            map.put(key, value);
            return;
        }
        if (map.size() >= capacity) {
            String oldest = insertionOrder.pollFirst();
            if (oldest != null) map.remove(oldest);
        }
        map.put(key, value);
        insertionOrder.addLast(key);
    }

    Optional<String> get(String key) { return Optional.ofNullable(map.get(key)); }
}
public class App {
    public static void main(String[] args) {
        BoundedCache cache = new BoundedCache(3);
        cache.put("a", "1");
        cache.put("b", "2");
        cache.put("c", "3");
        System.out.println("get('a'): " + cache.get("a"));
        cache.put("d", "4");  // evicts 'a' (oldest)
        System.out.println("get('d'): " + cache.get("d"));
        System.out.println("get('a'): " + cache.get("a"));
    }
}

