// Analytics: BlockingQueue + ConcurrentHashMap + AtomicLong

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.stream.*;
public class App {
    public static void main(String[] args) throws InterruptedException {
        BlockingQueue<String> requests = new LinkedBlockingQueue<>(50);
        ConcurrentHashMap<String, AtomicLong> counts = new ConcurrentHashMap<>();
        String[] endpoints = {"/api/orders","/api/users","/api/products","/api/search"};

        // Worker threads
        ExecutorService pool = Executors.newFixedThreadPool(3);
        AtomicInteger processed = new AtomicInteger(0);
        for (int w = 0; w < 3; w++) pool.submit(() -> {
            try {
                while (true) {
                    String ep = requests.poll(500, TimeUnit.MILLISECONDS);
                    if (ep == null) break;
                    counts.computeIfAbsent(ep, k -> new AtomicLong(0)).incrementAndGet();
                    processed.incrementAndGet();
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        // Produce 20 requests
        Random rnd = new Random(42);
        for (int i = 0; i < 20; i++)
            requests.put(endpoints[rnd.nextInt(endpoints.length)]);

        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);

        System.out.println("Top 3 endpoints:");
        counts.entrySet().stream()
            .sorted((a,b) -> Long.compare(b.getValue().get(), a.getValue().get()))
            .limit(3)
            .forEach(e -> System.out.println(e.getKey() + ": " + e.getValue().get()));
    }
}

