import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
// Connection pool using BlockingQueue

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
class ConnectionPool {
    private final BlockingQueue<String> pool;
    private final AtomicInteger activeCount = new AtomicInteger(0);

    ConnectionPool(int capacity) {
        pool = new LinkedBlockingQueue<>(capacity);
        for (int i = 1; i <= capacity; i++) pool.offer("C-" + i);
    }

    String getConnection() throws InterruptedException {
        String conn = pool.take();  // blocks if no connections available
        activeCount.incrementAndGet();
        return conn;
    }

    void releaseConnection(String conn) throws InterruptedException {
        pool.put(conn);
        activeCount.decrementAndGet();
    }

    int getActiveCount() { return activeCount.get(); }
    int getPoolSize()    { return pool.size(); }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        ConnectionPool connPool = new ConnectionPool(3);
        ExecutorService exec = Executors.newFixedThreadPool(5);

        for (int i = 1; i <= 5; i++) {
            final String tname = "Thread-" + i;
            exec.submit(() -> {
                try {
                    String conn = connPool.getConnection();
                    System.out.println(tname + " acquired " + conn);
                    Thread.sleep(100);
                    System.out.println(tname + " released " + conn);
                    connPool.releaseConnection(conn);
                } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            });
        }
        exec.shutdown();
        exec.awaitTermination(10, TimeUnit.SECONDS);
        System.out.println("All done. Active: " + connPool.getActiveCount() +
                           ", Pool: " + connPool.getPoolSize());
    }
}
